use crate::types::{DecideInput, DecideOutput};
use std::f64::consts::PI;

fn realcompare(a: f64, b: f64) -> &'static str {
    if a == b {
        return "EQ";
    }
    let max_abs = a.abs().max(b.abs());
    if max_abs == 0.0 {
        return "EQ";
    }
    let rel_diff = (a - b).abs() / max_abs;
    if rel_diff < 1e-6 {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x2 - x1).powi(2) + (y2 - y1).powi(2)).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs() / 2.0
}

fn min_enclosing_circle_radius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let a = dist(x1, y1, x2, y2);
    let b = dist(x2, y2, x3, y3);
    let c = dist(x3, y3, x1, y1);

    let mut sides = [a, b, c];
    sides.sort_by(|a, b| a.partial_cmp(b).unwrap());

    let sum_sq = sides[0] * sides[0] + sides[1] * sides[1];
    let max_sq = sides[2] * sides[2];

    if max_sq > sum_sq {
        sides[2] / 2.0
    } else {
        let area = triangle_area(x1, y1, x2, y2, x3, y3);
        if area == 0.0 {
            sides[2] / 2.0
        } else {
            a * b * c / (4.0 * area)
        }
    }
}

fn angle_at_vertex(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> Option<f64> {
    let dx1 = x1 - x2;
    let dy1 = y1 - y2;
    let dx2 = x3 - x2;
    let dy2 = y3 - y2;

    let len1 = (dx1 * dx1 + dy1 * dy1).sqrt();
    let len2 = (dx2 * dx2 + dy2 * dy2).sqrt();

    if len1 == 0.0 || len2 == 0.0 {
        return None;
    }

    let cos_angle = (dx1 * dx2 + dy1 * dy2) / (len1 * len2);
    let cos_angle = cos_angle.max(-1.0).min(1.0);
    Some(cos_angle.acos())
}

fn point_to_line_distance(px: f64, py: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    let dx = x2 - x1;
    let dy = y2 - y1;
    let len = (dx * dx + dy * dy).sqrt();
    if len == 0.0 {
        dist(px, py, x1, y1)
    } else {
        (dx * (py - y1) - dy * (px - x1)).abs() / len
    }
}

fn quadrant(x: f64, y: f64) -> usize {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let n = input.numpoints;
    let mut cmv = vec![false; 15];

    // LIC 1: Two consecutive points distance > LENGTH1
    for i in 0..n - 1 {
        let d = dist(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]);
        if realcompare(d, input.parameters.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2: Three consecutive points can't be contained in circle of radius RADIUS1
    for i in 0..n - 2 {
        let r = min_enclosing_circle_radius(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if realcompare(r, input.parameters.radius1) == "GT" {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3: Three consecutive points form angle outside [PI-EPSILON, PI+EPSILON]
    for i in 0..n - 2 {
        if let Some(angle) = angle_at_vertex(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        ) {
            let lower = PI - input.parameters.epsilon;
            let upper = PI + input.parameters.epsilon;
            if realcompare(angle, lower) == "LT" || realcompare(angle, upper) == "GT" {
                cmv[2] = true;
                break;
            }
        }
    }

    // LIC 4: Three consecutive points form triangle with area > AREA1
    for i in 0..n - 2 {
        let area = triangle_area(
            input.x[i],
            input.y[i],
            input.x[i + 1],
            input.y[i + 1],
            input.x[i + 2],
            input.y[i + 2],
        );
        if realcompare(area, input.parameters.area1) == "GT" {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5: Q_PTS consecutive points lie in more than QUADS quadrants
    let q_pts = input.parameters.q_pts;
    let quads = input.parameters.quads;
    for i in 0..=n - q_pts {
        let mut q1 = false;
        let mut q2 = false;
        let mut q3 = false;
        let mut q4 = false;
        for j in i..i + q_pts {
            match quadrant(input.x[j], input.y[j]) {
                1 => q1 = true,
                2 => q2 = true,
                3 => q3 = true,
                4 => q4 = true,
                _ => {}
            }
        }
        let count = q1 as usize + q2 as usize + q3 as usize + q4 as usize;
        if count > quads {
            cmv[4] = true;
            break;
        }
    }

    // LIC 6: Two consecutive points where X[j] - X[i] < 0
    for i in 0..n - 1 {
        if realcompare(input.x[i + 1], input.x[i]) == "LT" {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7: N_PTS consecutive points, at least one point > DIST from line
    if n >= 3 {
        let n_pts = input.parameters.n_pts;
        for i in 0..=n - n_pts {
            let first_x = input.x[i];
            let first_y = input.y[i];
            let last_x = input.x[i + n_pts - 1];
            let last_y = input.y[i + n_pts - 1];

            let mut found = false;
            for j in i..i + n_pts {
                let d = point_to_line_distance(
                    input.x[j], input.y[j], first_x, first_y, last_x, last_y,
                );
                if realcompare(d, input.parameters.dist) == "GT" {
                    found = true;
                    break;
                }
            }
            if found {
                cmv[6] = true;
                break;
            }
        }
    }

    // LIC 8: Two points separated by K_PTS intervening points, distance > LENGTH1
    if n >= 3 {
        let k_pts = input.parameters.k_pts;
        for i in 0..=n - k_pts - 2 {
            let j = i + k_pts + 1;
            let d = dist(input.x[i], input.y[i], input.x[j], input.y[j]);
            if realcompare(d, input.parameters.length1) == "GT" {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9: Three points separated by A_PTS and B_PTS, can't fit in circle of radius RADIUS1
    if n >= 5 {
        let a_pts = input.parameters.a_pts;
        let b_pts = input.parameters.b_pts;
        for i in 0..=n - a_pts - b_pts - 3 {
            let j = i + a_pts + 1;
            let k = j + b_pts + 1;
            let r = min_enclosing_circle_radius(
                input.x[i], input.y[i], input.x[j], input.y[j], input.x[k], input.y[k],
            );
            if realcompare(r, input.parameters.radius1) == "GT" {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10: Three points separated by C_PTS and D_PTS, angle outside [PI-EPSILON, PI+EPSILON]
    if n >= 5 {
        let c_pts = input.parameters.c_pts;
        let d_pts = input.parameters.d_pts;
        for i in 0..=n - c_pts - d_pts - 3 {
            let j = i + c_pts + 1;
            let k = j + d_pts + 1;
            if let Some(angle) = angle_at_vertex(
                input.x[i], input.y[i], input.x[j], input.y[j], input.x[k], input.y[k],
            ) {
                let lower = PI - input.parameters.epsilon;
                let upper = PI + input.parameters.epsilon;
                if realcompare(angle, lower) == "LT" || realcompare(angle, upper) == "GT" {
                    cmv[9] = true;
                    break;
                }
            }
        }
    }

    // LIC 11: Three points separated by E_PTS and F_PTS, triangle area > AREA1
    if n >= 5 {
        let e_pts = input.parameters.e_pts;
        let f_pts = input.parameters.f_pts;
        for i in 0..=n - e_pts - f_pts - 3 {
            let j = i + e_pts + 1;
            let k = j + f_pts + 1;
            let area = triangle_area(
                input.x[i], input.y[i], input.x[j], input.y[j], input.x[k], input.y[k],
            );
            if realcompare(area, input.parameters.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12: Two points separated by G_PTS intervening points, X[j] - X[i] < 0
    if n >= 3 {
        let g_pts = input.parameters.g_pts;
        for i in 0..=n - g_pts - 2 {
            let j = i + g_pts + 1;
            if realcompare(input.x[j], input.x[i]) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13: Two parts - distance > LENGTH1 and distance < LENGTH2 (both with K_PTS separation)
    if n >= 3 {
        let k_pts = input.parameters.k_pts;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..=n - k_pts - 2 {
            let j = i + k_pts + 1;
            let d = dist(input.x[i], input.y[i], input.x[j], input.y[j]);
            if realcompare(d, input.parameters.length1) == "GT" {
                part1 = true;
            }
            if realcompare(d, input.parameters.length2) == "LT" {
                part2 = true;
            }
            if part1 && part2 {
                break;
            }
        }
        cmv[12] = part1 && part2;
    }

    // LIC 14: Two parts - can't fit in RADIUS1 and can fit in RADIUS2 (both with A_PTS, B_PTS separation)
    if n >= 5 {
        let a_pts = input.parameters.a_pts;
        let b_pts = input.parameters.b_pts;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..=n - a_pts - b_pts - 3 {
            let j = i + a_pts + 1;
            let k = j + b_pts + 1;
            let r = min_enclosing_circle_radius(
                input.x[i], input.y[i], input.x[j], input.y[j], input.x[k], input.y[k],
            );
            if realcompare(r, input.parameters.radius1) == "GT" {
                part1 = true;
            }
            if realcompare(r, input.parameters.radius2) != "GT" {
                part2 = true;
            }
            if part1 && part2 {
                break;
            }
        }
        cmv[13] = part1 && part2;
    }

    // LIC 15: Two parts - area > AREA1 and area < AREA2 (both with E_PTS, F_PTS separation)
    if n >= 5 {
        let e_pts = input.parameters.e_pts;
        let f_pts = input.parameters.f_pts;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..=n - e_pts - f_pts - 3 {
            let j = i + e_pts + 1;
            let k = j + f_pts + 1;
            let area = triangle_area(
                input.x[i], input.y[i], input.x[j], input.y[j], input.x[k], input.y[k],
            );
            if realcompare(area, input.parameters.area1) == "GT" {
                part1 = true;
            }
            if realcompare(area, input.parameters.area2) == "LT" {
                part2 = true;
            }
            if part1 && part2 {
                break;
            }
        }
        cmv[14] = part1 && part2;
    }

    // PUM computation
    let mut pum = vec![vec![false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                match input.lcm[i][j].as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => {}
                }
            }
        }
    }

    // FUV computation
    let mut fuv = vec![false; 15];
    for i in 0..15 {
        if !pum[i][i] {
            fuv[i] = true;
        } else {
            fuv[i] = pum[i].iter().all(|&x| x);
        }
    }

    // Launch decision
    let launch = fuv.iter().all(|&x| x);

    DecideOutput {
        cmv,
        pum,
        fuv,
        launch,
    }
}
